 21→/// Direction(s) indicated by `..` notation.
 22→#[derive(Debug, Clone, PartialEq, Eq)]
 23→pub enum DotDirection {
 24→    /// No dots: just the revision itself.
 25→    None,
 26→    /// `x..` — ancestors (x at top, older below).
 27→    Ancestors,
 28→    /// `..x` — descendants (newer above, x at bottom).
 29→    Descendants,
 30→    /// `..x..` — both directions, x in the middle.
 31→    Both,
 32→}
 33→
 34→/// Result of parsing positional `..` notation.
 35→#[derive(Debug, Clone, PartialEq, Eq)]
 36→pub struct DotSpec {
 37→    /// The bare revision (without `..`).
 38→    pub rev: String,
 39→    /// Which direction(s) the dots indicate.
 40→    pub direction: DotDirection,
 41→    /// Count per dotted side (x is not counted).
 42→    pub count: usize,
 43→}
 44→
 45→/// Parse a positional REV string for `..` notation.
 46→///
 47→/// Returns the bare revision, direction, and default count (0).
 48→/// Count is set separately from the second positional arg.
 49→pub fn parse_dot_rev(rev: &str) -> DotSpec {
 50→    if let Some(inner) = rev.strip_prefix("..").and_then(|s| s.strip_suffix("..")) {
 51→        DotSpec {
 52→            rev: inner.to_string(),
 53→            direction: DotDirection::Both,
 54→            count: 0,
 55→        }
 56→    } else if let Some(inner) = rev.strip_prefix("..") {
 57→        DotSpec {
 58→            rev: inner.to_string(),
 59→            direction: DotDirection::Descendants,
 60→            count: 0,
 61→        }
 62→    } else if let Some(inner) = rev.strip_suffix("..") {
 63→        DotSpec {
 64→            rev: inner.to_string(),
 65→            direction: DotDirection::Ancestors,
 66→            count: 0,
 67→        }
 68→    } else {
 69→        DotSpec {
 70→            rev: rev.to_string(),
 71→            direction: DotDirection::None,
 72→            count: 0,
 73→        }
 74→    }
 75→}
 76→
 77→/// Resolve effective revision, limit, and whether results need reversing
 78→/// from positional args combined with named flags.
 79→///
 80→/// Named flags (`-r`, `-l`) take precedence over positional args.
 81→pub struct ResolvedArgs {
 82→    /// The jj revset string to evaluate.
 83→    pub revset: String,
 84→    /// Maximum number of commits to return (None = unlimited).
 85→    pub limit: Option<usize>,
 86→    /// For `..x..`, the count per side.
 87→    pub both_count: Option<usize>,
 88→    /// The bare primary revision (for highlighting).
 89→    pub primary_rev: String,
 90→}
 91→
 92→/// Resolve positional `..` args with named flag overrides.
 93→///
 94→/// - `pos_rev`: first positional arg (may contain `..`)
 95→/// - `pos_count`: second positional arg
 96→/// - `flag_rev`: `-r` flag value (if different from default)
 97→/// - `flag_limit`: `-l` flag value
 98→/// - `default_rev`: the default revision (e.g. "@")
 99→pub fn resolve_dot_args(
100→    pos_rev: Option<&str>,
101→    pos_count: Option<usize>,
102→    flag_rev: &str,
103→    flag_limit: Option<usize>,
104→    default_rev: &str,
105→) -> ResolvedArgs {
106→    // If named flags were explicitly set, they take full precedence
107→    let flag_rev_set = flag_rev != default_rev;
108→    let flag_limit_set = flag_limit.is_some();
109→
110→    if flag_rev_set || (flag_limit_set && pos_rev.is_none()) {
111→        return ResolvedArgs {
112→            revset: flag_rev.to_string(),
113→            limit: flag_limit,
114→            both_count: None,
115→            primary_rev: flag_rev.to_string(),
116→        };
117→    }
118→
119→    // Use positional args
120→    let rev_str = pos_rev.unwrap_or(default_rev);
121→    let mut spec = parse_dot_rev(rev_str);
122→
123→    // If there's a positional count, set it
124→    if let Some(c) = pos_count {
125→        spec.count = c;
126→    }
127→
128→    // Named limit overrides positional count
129→    if flag_limit_set {
130→        spec.count = flag_limit.unwrap();
131→    }
132→
133→    let primary = spec.rev.clone();
134→
135→    match spec.direction {
136→        DotDirection::None => {
137→            if spec.count > 0 {
138→                // bare `x 5` → `x.. 5` (ancestors)
139→                ResolvedArgs {
140→                    revset: format!("::{}", spec.rev),
141→                    limit: Some(spec.count + 1), // +1 for x itself
142→                    both_count: None,
143→                    primary_rev: primary,
144→                }
145→            } else {
146→                ResolvedArgs {
147→                    revset: spec.rev,
148→                    limit: Some(1),
149→                    both_count: None,
150→                    primary_rev: primary,
151→                }
152→            }
153→        }
154→        DotDirection::Ancestors => {
155→            if spec.count > 0 {
156→                ResolvedArgs {
157→                    revset: format!("::{}", spec.rev),
158→                    limit: Some(spec.count + 1),
159→                    both_count: None,
160→                    primary_rev: primary,
161→                }
162→            } else {
163→                ResolvedArgs {
164→                    revset: format!("::{}", spec.rev),
165→                    limit: None,
166→                    both_count: None,
167→                    primary_rev: primary,
168→                }
169→            }
170→        }
171→        DotDirection::Descendants => {
172→            if spec.count > 0 {
173→                ResolvedArgs {
174→                    revset: format!("{}::", spec.rev),
175→                    limit: Some(spec.count + 1),
176→                    both_count: None,
177→                    primary_rev: primary,
178→                }
179→            } else {
180→                ResolvedArgs {
181→                    revset: format!("{}::", spec.rev),
182→                    limit: None,
183→                    both_count: None,
184→                    primary_rev: primary,
185→                }
186→            }
187→        }
188→        DotDirection::Both => ResolvedArgs {
189→            revset: format!("::{}|{}::", spec.rev, spec.rev),
190→            limit: None,
191→            both_count: Some(spec.count),
192→            primary_rev: primary,
193→        },
194→    }
195→}
196→
197→/// Wrap text in ANSI bold escape codes.
198→pub fn bold(s: &str) -> String {
199→    format!("\x1b[1m{s}\x1b[0m")
200→}
201→
202→/// Bold only the first line of a multi-line string.
203→pub fn bold_first_line(s: &str) -> String {
204→    if let Some(pos) = s.find('\n') {
205→        format!("\x1b[1m{}\x1b[0m{}", &s[..pos], &s[pos..])
206→    } else {
207→        bold(s)
208→    }
209→}
210→
211→/// Format: just the short changeID.
212→pub fn format_chid(commit: &Commit) -> String {
213→    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
214→    change_hex[..change_hex.len().min(12)].to_string()
215→}
216→
217→/// Format: changeID commitID first-line (single line).
218→pub fn format_commit_short(commit: &Commit) -> String {
219→    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
220→    let change_short = &change_hex[..change_hex.len().min(12)];
221→    let commit_hex = commit.id().hex();
222→    let commit_short = &commit_hex[..commit_hex.len().min(12)];
223→    let first_line = commit.description().lines().next().unwrap_or("");
224→    if first_line.is_empty() {
225→        format!("{change_short} {commit_short} (no description set)")
226→    } else {
227→        format!("{change_short} {commit_short} {first_line}")
228→    }
229→}
230→
231→/// Format: changeID commitID first-line, then remaining description lines.
232→pub fn format_commit_full(commit: &Commit) -> String {
233→    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
234→    let change_short = &change_hex[..change_hex.len().min(12)];
235→    let commit_hex = commit.id().hex();
236→    let commit_short = &commit_hex[..commit_hex.len().min(12)];
237→    let desc = commit.description();
238→    if desc.is_empty() {
239→        format!("{change_short} {commit_short} (no description set)")
240→    } else {
241→        let mut lines = desc.lines();
242→        let first_line = lines.next().unwrap_or("");
243→        let mut result = format!("{change_short} {commit_short} {first_line}");
244→        for line in lines {
245→            result.push('\n');
246→            result.push_str(line);
247→        }
248→        result
249→    }
250→}
251→
252→/// Collect formatted lines for `..x..` (both directions).
253→///
254→/// `formatter` converts a `Commit` into a display string.
255→/// Returns `(lines, anchor_index)` — the lines in display order
256→/// (descendants newest first, anchor, ancestors newest first)
257→/// and the index of the anchor commit within the lines.
258→pub fn collect_both<F>(
259→    repo: &Arc<ReadonlyRepo>,
260→    repo_path: &Path,
261→    pos_rev: Option<&str>,
262→    both_count: usize,
263→    formatter: F,
264→) -> Result<(Vec<String>, usize), Box<dyn std::error::Error>>
265→where
266→    F: Fn(&Commit) -> String,
267→{
268→    let bare_rev = pos_rev.unwrap_or("@");
269→    let spec = parse_dot_rev(bare_rev);
270→    let (workspace, _) = load_repo(repo_path)?;
271→    let anchor_ids = resolve_revset(&workspace, repo, &spec.rev)?;
272→    if anchor_ids.is_empty() {
273→        return Err(format!("no commit found for revision '{}'", spec.rev).into());
274→    }
275→    let anchor_id = &anchor_ids[0];
276→    let root_commit_id = repo.store().root_commit_id().clone();
277→
278→    let ancestor_ids = resolve_revset(&workspace, repo, &format!("::{}", spec.rev))?;
279→    let descendant_ids = resolve_revset(&workspace, repo, &format!("{}::", spec.rev))?;
280→
281→    // Descendants (newest first from jj), excluding anchor
282→    let mut desc_lines: Vec<String> = Vec::new();
283→    for commit_id in &descendant_ids {
284→        if *commit_id == root_commit_id || *commit_id == *anchor_id {
285→            continue;
286→        }
287→        let commit = repo.store().get_commit(commit_id)?;
288→        desc_lines.push(formatter(&commit));
289→    }
290→    if both_count > 0 {
291→        let start = desc_lines.len().saturating_sub(both_count);
292→        desc_lines = desc_lines[start..].to_vec();
293→    } else {
294→        desc_lines.clear();
295→    }
296→
297→    // Anchor
298→    let anchor_commit = repo.store().get_commit(anchor_id)?;
299→
300→    // Ancestors (newest first from jj), excluding anchor
301→    let mut anc_lines: Vec<String> = Vec::new();
302→    if both_count > 0 {
303→        let mut count = 0;
304→        for commit_id in &ancestor_ids {
305→            if root_commit_id == *commit_id || *commit_id == *anchor_id {
306→                continue;
307→            }
308→            let commit = repo.store().get_commit(commit_id)?;
309→            anc_lines.push(formatter(&commit));
310→            count += 1;
311→            if count >= both_count {
312→                break;
313→            }
314→        }
315→    }
316→
317→    let anchor_index = desc_lines.len();
318→    let mut result = desc_lines;
319→    result.push(formatter(&anchor_commit));
320→    result.extend(anc_lines);
321→    Ok((result, anchor_index))
322→}
323→
324→pub fn load_repo(
325→    path: &Path,
326→) -> Result<(Workspace, Arc<ReadonlyRepo>), Box<dyn std::error::Error>> {
327→    let config = StackedConfig::with_defaults();
328→    let settings = UserSettings::from_config(config)?;
329→    let store_factories = StoreFactories::default();
330→    let working_copy_factories = default_working_copy_factories();
331→
332→    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
333→    let repo = workspace.repo_loader().load_at_head().block_on()?;
334→
335→    Ok((workspace, repo))
336→}
337→
338→/// Parse and evaluate a revset string, returning commit IDs.
339→pub fn resolve_revset(
340→    workspace: &Workspace,
341→    repo: &Arc<ReadonlyRepo>,
342→    revset_str: &str,
343→) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
344→    let aliases_map = RevsetAliasesMap::new();
345→    let fileset_aliases_map = FilesetAliasesMap::new();
346→    let extensions = RevsetExtensions::default();
347→    let workspace_root = workspace.workspace_root().to_path_buf();
348→    let path_converter = RepoPathUiConverter::Fs {
349→        cwd: workspace_root.clone(),
350→        base: workspace_root,
351→    };
352→    let workspace_name = workspace.workspace_name();
353→    let workspace_ctx = RevsetWorkspaceContext {
354→        path_converter: &path_converter,
355→        workspace_name,
356→    };
357→    let context = RevsetParseContext {
358→        aliases_map: &aliases_map,
359→        local_variables: HashMap::new(),
360→        user_email: "",
361→        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
362→        default_ignored_remote: None,
363→        fileset_aliases_map: &fileset_aliases_map,
364→        use_glob_by_default: false,
365→        extensions: &extensions,
366→        workspace: Some(workspace_ctx),
367→    };
368→
369→    let mut diagnostics = RevsetDiagnostics::new();
370→    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;
371→
372→    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
373→    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
374→    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
375→    let revset = resolved.evaluate(repo.as_ref())?;
376→
377→    let mut commit_ids = Vec::new();
378→    for result in revset.iter() {
379→        commit_ids.push(result?);
380→    }
381→    Ok(commit_ids)
382→}
