        } else {
            panic!("expected Finalize");
        }
    }

    #[test]
    fn finalize_partial_opts() {
        let cli = parse(&[
            "vc-x1",
            "finalize",
            "--bookmark",
            "main",
            "--repo",
            ".claude",
            "--push",
